module sync_binary_counter (CLK, RESET, Q);
input CLK;
input RESET;
output reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RESET) begin
        Q <= 4'b0000;
    end
    else begin
        Q <= Q + 1;
    end
end

endmodule
